mapper.select:
SELECT id, title, mode, start_name, start_lng, start_lat, end_name, end_lng, end_lat, via_json, distance, duration, created_at, updated_at FROM route_history
AND ( title LIKE CONCAT('%', #{keyword}, '%') OR start_name LIKE CONCAT('%', #{keyword}, '%') OR end_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY updated_at DESC, id DESC LIMIT #{limit}

SELECT id, title, mode, start_name, start_lng, start_lat, end_name, end_lng, end_lat,
       via_json, distance, duration, created_at, updated_at
FROM route_history
WHERE start_lng = #{startLng}
  AND start_lat = #{startLat}
  AND end_lng = #{endLng}
  AND end_lat = #{endLat}
  AND COALESCE(via_json, '') = COALESCE(#{viaJson}, '')
ORDER BY updated_at DESC, id DESC
LIMIT 1

mapper.update:
UPDATE route_history
SET updated_at = NOW()
WHERE id = #{id}

mapper.delete:
DELETE FROM route_history
WHERE id NOT IN (
    SELECT id FROM (
        SELECT id
        FROM route_history
        ORDER BY updated_at DESC, id DESC
        LIMIT #{limit}
    ) keep_ids
)
